public  static ETG_BankFormERController construct()
{
    return new ETG_BankFormERController();
}

public static void main(Args    _args)
{
    ETG_BankFormERController       bankFormController;
    ETGBillExchangeContract         billExchangeContract;
    CustInvoiceJour                 custInvoiceJour;

    bankFormController    =   ETG_BankFormERController::construct();
    custInvoiceJour                 =   _args.record() as CustInvoiceJour;

    bankFormController    =   new ETG_BankFormERController(
                                    classStr (ETG_BankFormERService),
                                    methodStr(ETG_BankFormERService , generateReportByGER),
                                    SysOperationExecutionMode::Synchronous);

    billExchangeContract      =   bankFormController.getDataContractObject();

    billExchangeContract.parmSalesInvoiceId(custInvoiceJour.InvoiceId);
    billExchangeContract.parmSalesId(custInvoiceJour.SalesId);
    billExchangeContract.parmCustInvoiceRecId(custInvoiceJour.RecId);

    bankFormController.parmArgs(_args);
    bankFormController.parmShowDialog(false);
    bankFormController.startOperation();
}
